CREATE TABLE public.workflow_ticket_stages (status text NOT NULL DEFAULT 'pending'::text, started_at timestamp without time zone, result text, handler_response jsonb, completed_at timestamp without time zone, review_notes text, reviewed_by character varying, ticket_id integer NOT NULL, updated_at timestamp without time zone NOT NULL DEFAULT now(), created_at timestamp without time zone NOT NULL DEFAULT now(), last_executed_at timestamp without time zone, error_message text, reviewed_at timestamp without time zone, id integer NOT NULL DEFAULT nextval('workflow_ticket_stages_id_seq'::regclass), last_executed_by character varying, stage_id integer NOT NULL, execution_count integer NOT NULL DEFAULT 0, review_decision text);
CREATE TABLE public.workflow_tickets (entity_type text NOT NULL, ticket_number character varying NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT now(), completed_at timestamp without time zone, entity_id integer NOT NULL, sub_status text, last_reviewed_at timestamp without time zone, priority text NOT NULL DEFAULT 'normal'::text, assigned_to_id character varying, risk_level text, status text NOT NULL DEFAULT 'submitted'::text, current_stage_id integer, last_reviewed_by character varying, started_at timestamp without time zone, submitted_at timestamp without time zone NOT NULL DEFAULT now(), due_at timestamp without time zone, review_count integer NOT NULL DEFAULT 0, workflow_definition_id integer NOT NULL, risk_score integer, metadata jsonb DEFAULT '{}'::jsonb, updated_at timestamp without time zone NOT NULL DEFAULT now(), id integer NOT NULL DEFAULT nextval('workflow_tickets_id_seq'::regclass), assigned_at timestamp without time zone);
CREATE TABLE public.workflow_transitions (to_stage_id integer, created_at timestamp without time zone NOT NULL DEFAULT now(), notes text, to_value text, transition_type text NOT NULL, id integer NOT NULL DEFAULT nextval('workflow_transitions_id_seq'::regclass), from_value text, from_stage_id integer, triggered_by_system boolean NOT NULL DEFAULT false, ticket_id integer NOT NULL, reason text, triggered_by character varying);